# ?? Playwright Chromium ?먮룞 ?ㅼ튂 (HuggingFace Space / ?쒕쾭 ?섍꼍) ??????????
# [OPT3] 理쒓꼍?됲솕: .pw_chromium_ok ?뚮옒洹??뚯씪???덉쑝硫?利됱떆 ?⑥뒪 (0ms)
# ?놁쓣 ?뚮쭔 諛깃렇?쇱슫?쒖뿉???ㅼ튂 ??遺??釉붾줈???꾩쟾 ?쒓굅
def _install_playwright_bg():
    try:
        _pw_flag = pathlib.Path.home() / ".pw_chromium_ok"
        if _pw_flag.exists():
            return  # ?뚮옒洹??덉쑝硫?利됱떆 醫낅즺
        import subprocess as _subprocess
        _pw_result = _subprocess.run(
            [sys.executable, "-m", "playwright", "install", "chromium", "--with-deps"],
            capture_output=True, text=True, timeout=180
        )
        if _pw_result.returncode == 0:
            _pw_flag.write_text("ok")
    except Exception:
        pass

try:
    import threading as _threading
    _threading.Thread(target=_install_playwright_bg, daemon=True).start()
except Exception:
    pass

# ?섍꼍蹂???꾩껜瑜?surrogate-safe?섍쾶 ?뺤젣 (???쒖옉 ??1?뚮쭔 ?ㅽ뻾)
try:
    for _ekey in list(os.environ.keys()):
        _eval = os.environ[_ekey]
        _safe_eval = _eval.encode("utf-8", errors="ignore").decode("utf-8")
        if _safe_eval != _eval:
            os.environ[_ekey] = _safe_eval
except Exception:
    pass

def _safe_str(obj) -> str:
    """surrogate 臾몄옄瑜??꾩쟾 ?쒓굅???덉쟾??臾몄옄??諛섑솚 ???꾩뿭 ?ъ슜"""
    try:
        s = obj if isinstance(obj, str) else str(obj)
        return s.encode("utf-8", errors="replace").decode("utf-8", errors="replace")
    except Exception:
        return repr(obj).encode("utf-8", errors="replace").decode("utf-8", errors="replace")

if hasattr(sys.stdout, "reconfigure"):
    try:
        sys.stdout.reconfigure(encoding="utf-8", errors="replace")
    except Exception:
        pass
if hasattr(sys.stderr, "reconfigure"):
    try:
        sys.stderr.reconfigure(encoding="utf-8", errors="replace")
    except Exception:
        pass

