def kcd_lookup(keyword: str) -> dict:
    """?먯뿰???ㅼ썙????KCD-8 肄붾뱶쨌遺꾨쪟 諛섑솚.
    ?꾩쟾 ?쇱튂 ?곗꽑, ?놁쑝硫?遺遺??ы븿 寃??
    諛섑솚: {"code": str, "category": str, "sub": str} ?먮뒗 {"code": "?뺤씤 ?꾩슂", ...}
    """
    kw = keyword.strip()
    if kw in _KCD8_REGISTRY:
        return _KCD8_REGISTRY[kw]
    for key, val in _KCD8_REGISTRY.items():
        if kw in key or key in kw:
            return val
    return {"code": "KCD 肄붾뱶 ?뺤씤 ?꾩슂", "category": "遺꾨쪟 遺덈챸?????꾨Ц媛 ?뺤씤 ?꾩슂", "sub": ""}

