def _check_admin_key(input_key: str) -> bool:
    """?낅젰 ?ㅺ? ADMIN_KEY / ADMIN_CODE / MASTER_CODE 以??섎굹? ?쇱튂?섎㈃ True"""
    k = (input_key or "").strip()
    if not k:
        return False
    valid = set()
    for _secret_name in ("ADMIN_KEY", "ADMIN_CODE", "MASTER_CODE"):
        try:
            v = st.secrets.get(_secret_name, "")
            if v:
                valid.add(v)
        except Exception:
            pass
        v2 = os.environ.get(_secret_name, "")
        if v2:
            valid.add(v2)
    # ???섎뱶肄붾뵫 ?대갚 ?덈? 湲덉? ??secrets/env 誘몄꽕????valid媛 鍮꾩뼱 ?덉쑝誘濡??먮룞 False 諛섑솚
    return k in valid

