def _get_sb_client():
    """Supabase ?대씪?댁뼵??諛섑솚 ???곌껐 ?ㅽ뙣 ??None 罹먯떆 諛⑹?
    ?곗꽑?쒖쐞 1: HF ?섍꼍蹂??SUPABASE_URL / SUPABASE_SERVICE_ROLE_KEY
    ?곗꽑?쒖쐞 2: secrets.toml [supabase] ?뱀뀡
    """
    if not _SB_PKG_OK:
        return None
    try:
        url = os.environ.get("SUPABASE_URL", "").strip()
        key = os.environ.get("SUPABASE_SERVICE_ROLE_KEY", "").strip()
        if not url or not key:
            try:
                _sb_sec = st.secrets.get("supabase", {})
                url = url or _sb_sec.get("url", "").strip()
                key = key or _sb_sec.get("service_role_key", "").strip()
            except Exception:
                pass
        if not url or not key:
            try:
                url = url or st.secrets.get("SUPABASE_URL", "").strip()
                key = key or st.secrets.get("SUPABASE_SERVICE_ROLE_KEY", "").strip()
            except Exception:
                pass
        if not url or not key:
            return None
        # url+key媛 ?덉쓣 ?뚮쭔 罹먯떆 ??None??罹먯떆?섎뒗 寃껋쓣 諛⑹?
        return _get_sb_client_cached(url, key)
    except Exception:
        return None

