@st.cache_resource
def get_client():
    # [GATE 1] API ?ㅻ뒗 諛섎뱶??gateway瑜??듯빐 ?쎌쓬 ??surrogate ?뺤젣 蹂댁옣
    if _GW_OK:
        api_key = _gw.get_secret("GEMINI_API_KEY")
    else:
        api_key = None
        try:
            api_key = st.secrets.get("GEMINI_API_KEY")
        except Exception:
            pass
        if not api_key:
            api_key = os.environ.get("GEMINI_API_KEY", "")
        api_key = api_key.encode("utf-8", errors="ignore").decode("utf-8")
    if not api_key:
        return None
    return _lazy_genai().Client(
        api_key=api_key,
        http_options={"api_version": "v1beta"}
    )

