def _rag_use_supabase() -> bool:
    """Supabase ?대씪?댁뼵?멸? ?ъ슜 媛?ν븳吏 ?뺤씤 (罹먯떆 ?놁쓬 ??False 罹먯떆 諛⑹?)"""
