                # [GATE 2] Cache-First ??紐⑤뜽 誘뱀뒪 Gemini ?몄텧 ??Safe Mode ?대갚
                import time as _time_mod

                # ?? STEP A: GCS 罹먯떆 議고쉶 (鍮꾩슜 0???곗꽑 寃쎈줈) ??????????????
                _cache_key = _gcs_cache_key(user_name, safe_q, product_key)
