# ?? ?먭? 吏꾨떒 ?ㅽ뻾 ?⑥닔 ???????????????????????????????????????????????????
def _run_self_diagnosis(force: bool = False, admin_mode: bool = False) -> list:
    """
    ?깅줉???먮윭 ?⑦꽩???쒗쉶?섎ŉ ?먮룞 ?먭? + ?섏젙.
    - ?몄뀡??1???ㅽ뻾 (force=True ??媛뺤젣 ?ъ떎??
    - admin_mode=False: 硫붾え由??곗궛留?(媛蹂? ???쇰컲 ?몄뀡 ?먮룞 ?ㅽ뻾??    - admin_mode=True: admin_only ??ぉ ?ы븿 ?꾩껜 ?ㅽ뻾 ??愿由ъ옄 ?섎룞 ?ㅽ뻾??    - ?섏젙????ぉ 紐⑸줉 諛섑솚
    """
    _DIAG_KEY = "_diag_done"
    if not force and st.session_state.get(_DIAG_KEY):
        return []

    fixed = []
    for rule in _ERROR_REGISTRY:
        # admin_only ??ぉ? admin_mode???뚮쭔 ?ㅽ뻾
        if rule.get("admin_only") and not admin_mode:
            continue
        try:
            if rule["check"]():
                rule["fix"]()
                log_error(f"?먭?吏꾨떒[?섏젙]", f"{rule['id']}: {rule['desc']}")
                fixed.append(rule["id"])
        except Exception as _de:
            log_error(f"?먭?吏꾨떒[?ㅻ쪟]", f"{rule['id']}: {_de}")

    st.session_state[_DIAG_KEY] = True
    return fixed

